import React, { useEffect, useMemo, useState } from "react"
import { useSortBy, useTable, useGlobalFilter } from "react-table"
import MOCK_DATA from "./MOCK_DATA.json"
import { COLUMNS } from "./columns"
import { Box, Paper, Table, TableBody, TableCell, TableContainer, TableHead, TableRow, Container, TableFooter } from '@material-ui/core'
import axios from 'axios';

function BasicTable() {
    const [students, setStudents] = useState([]);
  function showStudents() {
    axios.get('http://localhost:80/api/getStudents.php')
      .then((response) => {
        setStudents(response.data);
        if (response.data.Status == 'Invalid') {
          alert('Invalid User');
        } else {
          // navigate('/teacherDashboard')
        }
      })
  };
  useEffect(() => {
    showStudents();
  }, []);

    const columns = useMemo(() => COLUMNS, [])
    const data = useMemo(() => students, [students])

    const {
        getTableProps,
        getTableBodyProps,
        headerGroups,
        rows,
        footerGroups,
        prepareRow,
        state,
        setGlobalFilter
    } = useTable({
        columns,
        data
    },
    useGlobalFilter)

  return (
    <Box>
        <Container>
            <Paper>
            <TableContainer>
            <Table {...getTableProps}>
                <TableHead>
                {headerGroups.map((headerGroup) => (
                <TableRow {...headerGroup.getHeaderGroupProps()}>
                    {headerGroup.headers.map((column) => (
                        <TableCell {...column.getHeaderProps()}>
                            {column.render('Header')}
                            </TableCell>
                    ))}
                </TableRow>
            ))}
                </TableHead>
                <TableBody {...getTableBodyProps}>
                {rows.map((row) => {
                prepareRow(row)
                return (
                    <TableRow {...row.getRowProps()}>
                        {row.cells.map((cell) => {
                            return (
                                <TableCell {...cell.getCellProps()}>{cell.render("Cell")}</TableCell>
                            )
                        })}
                    </TableRow>
                )
            })}
                </TableBody>
                {/* <TableFooter>
                        {footerGroups.map((footerGroup) => (
                            <TableRow {...footerGroup.getFooterGroupProps()}>
                                {footerGroup.headers.map((column) => (
                                    <TableCell {...column.getFooterProps()}>
                                        {column.render('Footer')}
                                    </TableCell>
                                ))}
                            </TableRow>
                        ))}
                </TableFooter> */}
            </Table>
        </TableContainer>
            </Paper>
        </Container>
        

    {/* <table {...getTableProps}>
        <thead>
            {headerGroups.map((headerGroup) => (
                <tr {...headerGroup.getHeaderGroupProps()}>
                    {headerGroup.headers.map((column) => (
                        <th {...column.getHeaderProps()}>{column.render('Header')}</th>
                    ))}
                </tr>
            ))}
        </thead>
        <tbody {...getTableBodyProps}>
            {rows.map((row) => {
                prepareRow(row)
                return (
                    <tr {...row.getRowProps()}>
                        {row.cells.map((cell) => {
                            return (
                                <td {...cell.getCellProps()}>{cell.render("Cell")}</td>
                            )
                        })}
                    </tr>
                )
            })}
            
        </tbody>
    </table> */}
    </Box>
  )
}

export default BasicTable
